{
  "content": "You are a concise financial assistant.

=== KPI SUMMARY ===
{{kpiSummary}}

=== RECENT ANOMALIES ===
{{anomalySummary}}

=== RELATED ENTITIES ===
{{entityGraph}}

Answer in 2-3 sentences maximum."
}

{
  "query": "query RevenueByMonth($year: Int!) {
  revenueByMonth(year: $year) {
    month year revenue currency
  }
}",
  "variables": { "year": 2026 }
}

{
  "query": "query ExpenseBreakdown($from: String!, $to: String!) {
  expenseBreakdown(from: $from, to: $to) {
    category vendorId vendorName total currency
  }
}",
  "variables": { "from": "2025-11-01T00:00:00Z", "to": "2026-03-31T23:59:59Z" }
}

{
  "query": "query CashPosition($asOf: String) {
  cashPosition(asOf: $asOf) {
    balance currency asOf
  }
}",
  "variables": { "asOf": "2026-03-31" }
}

{
  "query": "query Anomalies($types: [String], $minScore: Float) {
  anomalies(types: $types, minScore: $minScore) {
    id
    type
    score
    confidence
    explanation
    relatedIds
    detectedAt
  }
}",
  "variables": { "types": ["EXPENSE_SPIKE", "DUPLICATE_INVOICE"], "minScore": 0.5 }
}

{
  "query": "query Anomaly($id: ID!) {
  anomaly(id: $id) {
    id
    type
    score
    confidence
    explanation
    relatedIds
    detectedAt
  }
}",
  "variables": { "id": "{{insightId}}" }
}

{
  "query": "mutation {
  createChatSession {
    id
    createdAt
    messages {
      id
      role
      content
      createdAt
    }
  }
}"
}

{
  "query": "query ChatSession($id: ID!) {
  chatSession(id: $id) {
    id
    createdAt
    messages {
      id
      sessionId
      role
      content
      latencyMs
      createdAt
    }
  }
}",
  "variables": { "id": "{{sessionId}}" }
}

{
  "query": "mutation SendMessage($sessionId: ID!, $text: String!) {
  sendMessage(sessionId: $sessionId, text: $text) {
    id
    sessionId
    role
    content
    latencyMs
    createdAt
  }
}",
  "variables": { "sessionId": "{{sessionId}}", "text": "What is our current cash position and any unusual expenses this month?" }
}

{
  "query": "query EntitySearch($question: String!) {
  entitySearch(question: $question) {
    id
    type
    externalId
    label
    meta
  }
}",
  "variables": { "question": "Who are our top suppliers?" }
}

{
  "query": "query($department: String, $from: String, $to: String) { headcount(department: $department, from: $from, to: $to) }",
  "variables": {
    "department": "Engineering",
    "from": "2026-01-01",
    "to": "2026-03-31"
  }
}

{
  "query": "query($department: String, $status: String, $limit: Float, $offset: Float) { employees(department: $department, status: $status, limit: $limit, offset: $offset) }",
  "variables": {
    "department": null,
    "status": "active",
    "limit": 50,
    "offset": 0
  }
}

{
  "query": "mutation SubmitFeedback($insightId: ID!, $rating: String!, $comment: String) {
  submitFeedback(insightId: $insightId, rating: $rating, comment: $comment) {
    id
    insightId
    rating
    comment
    createdAt
  }
}",
  "variables": { "insightId": "{{insightId}}", "rating": "helpful", "comment": "Correctly identified a real duplicate." }
}

{
  "query": "query($category: String, $status: String, $limit: Float, $offset: Float) { assetStatus(category: $category, status: $status, limit: $limit, offset: $offset) }",
  "variables": {
    "category": null,
    "status": null,
    "limit": 50,
    "offset": 0
  }
}
